import scala.collection.mutable.PriorityQueue

def solve(n: Long, edges: Array[Array[Long]]): Long = {
  val adj = Array.ofDim[Array[(Int, Int, Int)]](n.toInt)
  for (edge <- edges) {
    val u = edge(0).toInt
    val v = edge(1).toInt
    val s = edge(2).toInt
    val e = edge(3).toInt
    adj(u) = adj(u) :+ (v, s, e)
  }

  val dist = Array.fill(n.toInt)(Long.MaxValue)
  dist(0) = 0L

  val pq = PriorityQueue[(Long, Int)]()
  pq.add((0L, 0))

  while (pq.nonEmpty) {
    val (t, u) = pq.pop()
    if (u == n.toInt - 1) return t
    if (t > dist(u)) continue
    for (edge <- adj(u)) {
      val (v, s, e) = edge
      if (t <= e) {
        val new_time = Math.max(t, s) + 1
        if (new_time < dist(v)) {
          dist(v) = new_time
          pq.add((new_time, v))
        }
      }
    }
  }

  -1L
}
